// ─────────────────────────────────────────────────────────────────────────────
// 符格 · Fuge —— 符籙紙段之律（本庫之「量度」）
// 符無 T1419 之經。考據裁斷（docs/考據/符籙總綱.md 五，2026-07-12）：
// 四段之制古典道藏無明文，四段名本天師門口教（張智雄〈書符與靈驗〉，
// 《輔仁宗教研究》16期，2007，頁87–108）；縱段比例・紙寬高比古典皆無可據。
// 故本卷數值係〔近人擬值〕——內部一致之工作格，永不升「已核」，
// 不得偽稱道藏所載之制。誦戒（段界遞增・盡於紙末）為內部一致性律，與出典無涉。
// ─────────────────────────────────────────────────────────────────────────────
export const 紙 = {
    寬: 24, // 一符之寬（指單位，承粉本格語）
    高: 72, // 寬一高三之基〔近人擬值・古典無寬高比明文；黃紙硃書乃後世通行，非早期道藏唯一制——早期隨科用色各異（總綱二・2.3）〕
};
// 縱段四分（z 自紙頂 0 至紙末 高）——〔近人擬值・四段名口傳有據而比例無典，總綱一〕
export const 段 = {
    符頭末: 12, // 0–12：符頭（三清諱「三勾」／「雨」蓋／敕令二字位——符首之制見總綱一・1.3）
    符身末: 44, // 12–44：符身（雲篆・複文・諱字疊書）
    符膽末: 56, // 44–56：符膽（密核；「符膽」語出民間法教口傳，非道藏——總綱一・1.1）
    符腳末: 72, // 56–72：符腳（叉腳押煞）
};
const 序 = [0, 段.符頭末, 段.符身末, 段.符膽末, 段.符腳末];
for (let i = 1; i < 序.length; i++) {
    if (!(序[i] > 序[i - 1]))
        throw new Error(`符格誦戒破：段界不遞增（${序[i - 1]}→${序[i]}）`);
}
if (段.符腳末 !== 紙.高)
    throw new Error('符格誦戒破：末段不盡於紙末');
